import ScrollReveal from 'scrollreveal';

const defaultProps = {
    easing: 'cubic-bezier(0.5, 0, 0, 1)',
    distance: '30px',
    duration: 1000,
    desktop: true,
    mobile: true
};

export default function initScrollReveal() {
    ScrollReveal().reveal('.load-hidden', defaultProps);
}
